<template>
  <div class="take-survey-container">
    <div v-if="loading" class="loading">⏳ Загрузка опросника...</div>
    
    <div v-else-if="error" class="error">❌ {{ error }}</div>
    
    <div v-else-if="submitted" class="success">
      <h2>✅ Спасибо за участие!</h2>
      <p>Ваши ответы успешно отправлены.</p>
    </div>
    
    <div v-else class="survey-form">
      <div class="survey-header">
        <h1>{{ survey.title }}</h1>
        <div class="survey-info">
          <span class="survey-type">{{ survey.survey_type.toUpperCase() }}</span>
          <span v-if="survey.deadline" class="deadline">
            Срок: {{ formatDate(survey.deadline) }}
          </span>
        </div>
      </div>
      
      <div class="progress-bar">
        <div class="progress" :style="{ width: progressPercent + '%' }"></div>
      </div>
      
      <div class="question-container">
        <div v-if="currentQuestion" class="question">
          <h3>{{ currentQuestion.question }}</h3>
          
          <input v-if="currentQuestion.type === 'text'" 
                 v-model="answers[currentQuestion.id]"
                 type="text"
                 class="text-input"
                 :required="currentQuestion.required" />
          
          <textarea v-if="currentQuestion.type === 'textarea'"
                    v-model="answers[currentQuestion.id]"
                    class="textarea-input"
                    rows="4"
                    :required="currentQuestion.required"></textarea>
          
          <div v-if="currentQuestion.type === 'radio'" class="radio-options">
            <label v-for="option in currentQuestion.options" :key="typeof option === 'object' ? option.value : option" class="radio-label">
              <input type="radio" 
                     :value="typeof option === 'object' ? option.value : option" 
                     v-model="answers[currentQuestion.id]"
                     :required="currentQuestion.required" />
              <span>{{ typeof option === 'object' ? option.text : option }}</span>
            </label>
          </div>
          
          <div v-if="currentQuestion.type === 'scale'" class="scale-options">
            <div class="scale-labels">
              <span>{{ scaleEdgeLow(currentQuestion) }}</span>
              <span>{{ scaleEdgeHigh(currentQuestion) }}</span>
            </div>
            <div class="scale-buttons">
              <button
                v-for="value in scaleValues(currentQuestion)"
                :key="value"
                type="button"
                :class="{ active: answers[currentQuestion.id] == value }"
                @click="answers[currentQuestion.id] = value"
                class="scale-btn"
              >
                {{ value }}
              </button>
            </div>
          </div>
          
          <div v-if="currentQuestion.type === 'matrix'" class="matrix-rating">
            <div class="matrix-header">
              <div class="matrix-scale-labels">
                <span class="empty-cell"></span>
                <span v-for="(label, idx) in (currentQuestion.columns || currentQuestion.scale || [])" :key="idx" class="scale-label">
                  {{ typeof label === 'object' ? label.text : label }}
                </span>
              </div>
            </div>
            
            <div v-for="(row, rowIdx) in (currentQuestion.rows || [])" :key="rowIdx" class="matrix-row">
              <div class="row-label">{{ typeof row === 'object' ? row.text : row }}</div>
              <div class="row-options">
                <label v-for="(label, colIdx) in (currentQuestion.columns || currentQuestion.scale || [])" :key="colIdx" class="matrix-option">
                  <input type="radio" 
                         :name="`matrix_${currentQuestion.id}_${rowIdx}`"
                         :value="typeof label === 'object' ? label.value : label"
                         v-model="matrixAnswers[currentQuestion.id][typeof row === 'object' ? row.value : row]" />
                  <span class="radio-custom"></span>
                </label>
              </div>
            </div>
          </div>
        </div>
        
        <div class="navigation-buttons">
          <button v-if="currentQuestionIndex > 0" 
                  @click="previousQuestion" 
                  class="nav-btn prev-btn">
            ← Назад
          </button>
          
          <button v-if="currentQuestionIndex < survey.questions.length - 1" 
                  @click="nextQuestion" 
                  class="nav-btn next-btn"
                  :disabled="!isCurrentQuestionAnswered">
            Далее →
          </button>
          
          <button v-if="currentQuestionIndex === survey.questions.length - 1" 
                  @click="submitSurvey" 
                  class="nav-btn submit-btn"
                  :disabled="!allRequiredAnswered">
            Отправить ответы
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios'

export default {
  name: 'SurveyTaker',
  data() {
    return {
      survey: null,
      loading: true,
      error: null,
      submitted: false,
      currentQuestionIndex: 0,
      answers: {},
      matrixAnswers: {}
    }
  },
  
  computed: {
    currentQuestion() {
      return this.survey?.questions[this.currentQuestionIndex]
    },
    
    progressPercent() {
      if (!this.survey) return 0
      return ((this.currentQuestionIndex + 1) / this.survey.questions.length) * 100
    },
    
    isCurrentQuestionAnswered() {
      const question = this.currentQuestion
      if (!question) return false
      
      if (question.type === 'matrix') {
        const matrixData = this.matrixAnswers[question.id] || {}
        return question.required
          ? question.rows.every(row => matrixData[this.matrixRowKey(row)])
          : true
      }
      
      return question.required ? 
        (this.answers[question.id] !== undefined && this.answers[question.id] !== '') : 
        true
    },
    
    allRequiredAnswered() {
      return this.survey?.questions.every(question => {
        if (!question.required) return true
        
        if (question.type === 'matrix') {
          const matrixData = this.matrixAnswers[question.id] || {}
          return question.rows.every(row => matrixData[this.matrixRowKey(row)])
        }
        
        return this.answers[question.id] !== undefined && this.answers[question.id] !== ''
      })
    }
  },
  
  async mounted() {
    await this.loadSurvey()
  },
  
  methods: {
    matrixRowKey(row) {
      return typeof row === 'object' && row !== null ? row.value : row
    },

    scaleValues(question) {
      if (!question || question.type !== 'scale') return []
      if (Array.isArray(question.scale) && question.scale.length) {
        return question.scale.map((v) => Number(v)).filter((n) => !Number.isNaN(n))
      }
      const mn = question.min != null ? Number(question.min) : 1
      const mx = question.max != null ? Number(question.max) : 5
      if (Number.isNaN(mn) || Number.isNaN(mx) || mn > mx) {
        return [1, 2, 3, 4, 5]
      }
      const out = []
      for (let i = mn; i <= mx; i++) out.push(i)
      return out
    },

    scaleEdgeLow(question) {
      const vals = this.scaleValues(question)
      if (!vals.length) return '1 (Низко)'
      return `${vals[0]} (Низко)`
    },

    scaleEdgeHigh(question) {
      const vals = this.scaleValues(question)
      if (!vals.length) return '5 (Высоко)'
      return `${vals[vals.length - 1]} (Высоко)`
    },

    async loadSurvey() {
      try {
        const token = this.$route.params.token
        const response = await axios.get(`/api/survey/${token}`)
        this.survey = response.data
        
        this.survey.questions.forEach(question => {
          if (question.type === 'matrix') {
            this.matrixAnswers[question.id] = {}
          }
        })
        
      } catch (error) {
        console.error('Error loading survey:', error)
        this.error = error.response?.data?.error || 'Ошибка загрузки опросника'
      } finally {
        this.loading = false
      }
    },
    
    nextQuestion() {
      if (this.currentQuestionIndex < this.survey.questions.length - 1) {
        this.currentQuestionIndex++
      }
    },
    
    previousQuestion() {
      if (this.currentQuestionIndex > 0) {
        this.currentQuestionIndex--
      }
    },
    
    async submitSurvey() {
      try {
        const token = this.$route.params.token
        
        const allAnswers = { ...this.answers }
        Object.keys(this.matrixAnswers).forEach(questionId => {
          allAnswers[questionId] = this.matrixAnswers[questionId]
        })
        
        await axios.post(`/api/survey/${token}/submit`, {
          answers: allAnswers,
          respondent_name: this.answers[1]
        })
        
        this.submitted = true
        
      } catch (error) {
        console.error('Error submitting survey:', error)
        alert('Ошибка отправки ответов')
      }
    },
    
    formatDate(dateString) {
      return new Date(dateString).toLocaleDateString('ru-RU')
    }
  }
}
</script>

